SELECT COUNT(1)
FROM sys_dict_type
WHERE dict_code = #{dictCode}
  AND deleted = 0

      AND id != #{excludeId}

mapper.insert:
INSERT INTO sys_dict_type (
    dict_code, dict_name, status, create_by, create_time, update_by, update_time, deleted, version
) VALUES (
    #{dictCode}, #{dictName}, #{status}, #{createBy}, NOW(), #{updateBy}, NOW(), 0, 0
)

mapper.select:
SELECT COUNT(1) FROM sys_dict_type d WHERE d.deleted = 0
AND (d.dict_code LIKE CONCAT('%', #{query.keyword}, '%') OR d.dict_name LIKE CONCAT('%', #{query.keyword}, '%'))
AND d.status = #{query.status}

SELECT FROM sys_dict_type d WHERE d.deleted = 0
AND (d.dict_code LIKE CONCAT('%', #{query.keyword}, '%') OR d.dict_name LIKE CONCAT('%', #{query.keyword}, '%'))
AND d.status = #{query.status}
